namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string CourseCode { get; set; } = string.Empty;
    public string Title { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public bool IsFeatured { get; set; }
}

namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Abbreviation { get; set; } = string.Empty;
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100)]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^\d{6,10}$", ErrorMessage = "Student ID must be 6-10 digits.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments =
    [
        new() { Id = 1, Name = "Computer Science", Abbreviation = "CS" },
        new() { Id = 2, Name = "Mathematics", Abbreviation = "MATH" },
        new() { Id = 3, Name = "Physics", Abbreviation = "PHYS" },
        new() { Id = 4, Name = "English", Abbreviation = "ENG" },
        new() { Id = 5, Name = "History", Abbreviation = "HIST" }
    ];

    private readonly List<Course> _courses =
    [
        new()
        {
            Id = 1, CourseCode = "CS 101", Title = "Introduction to Programming",
            Description = "Learn the fundamentals of programming using C#. Topics include variables, control structures, object-oriented design, and basic algorithms.",
            Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", DepartmentId = 1, IsFeatured = true,
            InstructorName = "Dr. Sarah Chen",
            InstructorBio = "Dr. Chen holds a Ph.D. in Computer Science from MIT and has 15 years of teaching experience specializing in introductory programming and software engineering."
        },
        new()
        {
            Id = 2, CourseCode = "CS 201", Title = "Data Structures and Algorithms",
            Description = "Study of fundamental data structures including arrays, linked lists, trees, graphs, and hash tables. Analysis of algorithm complexity.",
            Credits = 4, Schedule = "Tue/Thu 10:30–11:50 AM", DepartmentId = 1, IsFeatured = true,
            InstructorName = "Dr. James Park",
            InstructorBio = "Dr. Park is an ACM Distinguished Educator with research in algorithm optimization and computational theory."
        },
        new()
        {
            Id = 3, CourseCode = "CS 310", Title = "Database Systems",
            Description = "Relational database design, SQL, normalization, indexing, and transaction management. Includes a semester-long project building a full database application.",
            Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", DepartmentId = 1, IsFeatured = false,
            InstructorName = "Prof. Maria Gonzalez",
            InstructorBio = "Prof. Gonzalez worked as a database architect at Oracle for 10 years before joining academia. She focuses on distributed systems and data modeling."
        },
        new()
        {
            Id = 4, CourseCode = "MATH 151", Title = "Calculus I",
            Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.",
            Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", DepartmentId = 2, IsFeatured = true,
            InstructorName = "Dr. Alan Whitfield",
            InstructorBio = "Dr. Whitfield has published extensively on mathematical pedagogy and received the university's Excellence in Teaching award three times."
        },
        new()
        {
            Id = 5, CourseCode = "MATH 252", Title = "Linear Algebra",
            Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to systems of equations.",
            Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", DepartmentId = 2, IsFeatured = false,
            InstructorName = "Dr. Priya Sharma",
            InstructorBio = "Dr. Sharma's research spans abstract algebra and its applications in cryptography and machine learning."
        },
        new()
        {
            Id = 6, CourseCode = "PHYS 101", Title = "General Physics I",
            Description = "Mechanics, thermodynamics, and waves. Includes weekly laboratory sessions with hands-on experiments.",
            Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM + Lab Fri 1:00–3:00 PM", DepartmentId = 3, IsFeatured = false,
            InstructorName = "Dr. Robert Kim",
            InstructorBio = "Dr. Kim is an experimental physicist whose research in quantum optics has been funded by the NSF for over a decade."
        },
        new()
        {
            Id = 7, CourseCode = "PHYS 220", Title = "Electromagnetism",
            Description = "Electric fields, magnetic fields, Maxwell's equations, and electromagnetic waves. Prerequisite: PHYS 101 and MATH 151.",
            Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", DepartmentId = 3, IsFeatured = true,
            InstructorName = "Dr. Lisa Nguyen",
            InstructorBio = "Dr. Nguyen completed postdoctoral work at CERN and brings real-world particle physics experience to the classroom."
        },
        new()
        {
            Id = 8, CourseCode = "ENG 110", Title = "Academic Writing",
            Description = "Develop critical reading and writing skills for academic contexts. Focus on argument construction, research methods, and clear prose.",
            Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:20 PM", DepartmentId = 4, IsFeatured = false,
            InstructorName = "Prof. David Hart",
            InstructorBio = "Prof. Hart is a published author and composition specialist who has directed the university writing center for eight years."
        },
        new()
        {
            Id = 9, CourseCode = "ENG 250", Title = "American Literature",
            Description = "Survey of American literature from the colonial period to the present, exploring themes of identity, freedom, and social change.",
            Credits = 3, Schedule = "Tue/Thu 2:30–3:50 PM", DepartmentId = 4, IsFeatured = false,
            InstructorName = "Dr. Angela Brooks",
            InstructorBio = "Dr. Brooks specializes in 20th-century American fiction and has published two monographs on the Harlem Renaissance."
        },
        new()
        {
            Id = 10, CourseCode = "HIST 101", Title = "World History to 1500",
            Description = "Survey of world civilizations from antiquity through the late medieval period, including Mesopotamia, Greece, Rome, China, and the Islamic world.",
            Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", DepartmentId = 5, IsFeatured = false,
            InstructorName = "Dr. Thomas Okafor",
            InstructorBio = "Dr. Okafor is a historian of the ancient Mediterranean whose archaeological fieldwork spans sites in Egypt and Turkey."
        }
    ];

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses(string? searchTerm = null, int? departmentId = null)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.CourseCode.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real application, this would persist to a database.
        return request.CourseId > 0
            && !string.IsNullOrWhiteSpace(request.StudentName)
            && !string.IsNullOrWhiteSpace(request.StudentId);
    }
}

