@page "/"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<div class="container">
    <div class="text-center my-4">
        <h1>University Course Catalog</h1>
        <p class="lead">Explore our departments and find the courses that fit your academic goals.</p>
    </div>

    <section class="mb-5">
        <h2>Featured Courses</h2>
        <div class="row">
            @foreach (var course in featuredCourses)
            {
                <div class="col-md-6 col-lg-4 mb-3">
                    <div class="card h-100">
                        <div class="card-body">
                            <h5 class="card-title">@course.CourseCode</h5>
                            <h6 class="card-subtitle mb-2 text-muted">@course.Title</h6>
                            <p class="card-text">@course.Credits credits &middot; @course.InstructorName</p>
                            <a href="/courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    </section>

    <section class="mb-5">
        <h2>Departments</h2>
        <div class="row">
            @foreach (var dept in departments)
            {
                <div class="col-md-4 col-lg-3 mb-3">
                    <a href="/courses?departmentId=@dept.Id" class="text-decoration-none">
                        <div class="card text-center h-100">
                            <div class="card-body">
                                <h5 class="card-title">@dept.Abbreviation</h5>
                                <p class="card-text">@dept.Name</p>
                            </div>
                        </div>
                    </a>
                </div>
            }
        </div>
    </section>
</div>

@code {
    private List<Course> featuredCourses = [];
    private List<Department> departments = [];

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetDepartments();
    }
}

