@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@rendermode InteractiveServer
@inject CatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Browse Courses</PageTitle>

<div class="container">
    <h1 class="my-4">Browse Courses</h1>

    <div class="row mb-4">
        <div class="col-md-6">
            <input type="text" class="form-control" placeholder="Search by title, code, or instructor..."
                   @bind="searchTerm" @bind:event="oninput" />
        </div>
        <div class="col-md-4">
            <select class="form-select" @bind="selectedDepartmentId">
                <option value="0">All Departments</option>
                @foreach (var dept in departments)
                {
                    <option value="@dept.Id">@dept.Name</option>
                }
            </select>
        </div>
    </div>

    @if (filteredCourses.Count == 0)
    {
        <div class="alert alert-info">No courses match your search criteria.</div>
    }
    else
    {
        <table class="table table-striped table-hover">
            <thead>
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th>Schedule</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in filteredCourses)
                {
                    <tr>
                        <td>@course.CourseCode</td>
                        <td>@course.Title</td>
                        <td>@course.Credits</td>
                        <td>@course.InstructorName</td>
                        <td>@course.Schedule</td>
                        <td><a href="/courses/@course.Id" class="btn btn-outline-primary btn-sm">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    }
</div>

@code {
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Department> departments = [];
    private List<Course> filteredCourses = [];
    private string _searchTerm = string.Empty;
    private int _selectedDepartmentId;

    private string searchTerm
    {
        get => _searchTerm;
        set { _searchTerm = value; ApplyFilters(); }
    }

    private int selectedDepartmentId
    {
        get => _selectedDepartmentId;
        set { _selectedDepartmentId = value; ApplyFilters(); }
    }

    protected override void OnInitialized()
    {
        departments = CatalogService.GetDepartments();
        _selectedDepartmentId = DepartmentId ?? 0;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        int? deptFilter = _selectedDepartmentId > 0 ? _selectedDepartmentId : null;
        string? search = string.IsNullOrWhiteSpace(_searchTerm) ? null : _searchTerm;
        filteredCourses = CatalogService.GetCourses(search, deptFilter);
    }
}

@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

<div class="container">
    @if (course is null)
    {
        <div class="alert alert-warning my-4">Course not found.</div>
    }
    else
    {
        <nav aria-label="breadcrumb" class="my-3">
            <ol class="breadcrumb">
                <li class="breadcrumb-item"><a href="/courses">Courses</a></li>
                <li class="breadcrumb-item active">@course.CourseCode</li>
            </ol>
        </nav>

        <h1>@course.CourseCode &mdash; @course.Title</h1>

        <div class="row mt-4">
            <div class="col-md-8">
                <h4>Description</h4>
                <p>@course.Description</p>

                <h4 class="mt-4">Schedule</h4>
                <p>@course.Schedule</p>

                <h4 class="mt-4">Instructor</h4>
                <p><strong>@course.InstructorName</strong></p>
                <p>@course.InstructorBio</p>
            </div>
            <div class="col-md-4">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">Course Info</h5>
                        <ul class="list-unstyled">
                            <li><strong>Code:</strong> @course.CourseCode</li>
                            <li><strong>Credits:</strong> @course.Credits</li>
                            <li><strong>Department:</strong> @(department?.Name ?? "Unknown")</li>
                        </ul>
                        <a href="/enroll?courseId=@course.Id" class="btn btn-success w-100 mt-3">Request Enrollment</a>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;
    private Department? department;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
        if (course is not null)
            department = CatalogService.GetDepartment(course.DepartmentId);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<div class="container">
    <h1 class="my-4">Enrollment Request</h1>

    @if (submitted)
