@page "/courses/{Id:int}"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

<div class="container">
    @if (course is null)
    {
        <div class="alert alert-warning my-4">Course not found.</div>
    }
    else
    {
        <nav aria-label="breadcrumb" class="my-3">
            <ol class="breadcrumb">
                <li class="breadcrumb-item"><a href="/courses">Courses</a></li>
                <li class="breadcrumb-item active">@course.CourseCode</li>
            </ol>
        </nav>

        <h1>@course.CourseCode &mdash; @course.Title</h1>

        <div class="row mt-4">
            <div class="col-md-8">
                <h4>Description</h4>
                <p>@course.Description</p>

                <h4 class="mt-4">Schedule</h4>
                <p>@course.Schedule</p>

                <h4 class="mt-4">Instructor</h4>
                <p><strong>@course.InstructorName</strong></p>
                <p>@course.InstructorBio</p>
            </div>
            <div class="col-md-4">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">Course Info</h5>
                        <ul class="list-unstyled">
                            <li><strong>Code:</strong> @course.CourseCode</li>
                            <li><strong>Credits:</strong> @course.Credits</li>
                            <li><strong>Department:</strong> @(department?.Name ?? "Unknown")</li>
                        </ul>
                        <a href="/enroll?courseId=@course.Id" class="btn btn-success w-100 mt-3">Request Enrollment</a>
                    </div>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;
    private Department? department;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourse(Id);
        if (course is not null)
            department = CatalogService.GetDepartment(course.DepartmentId);
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@inject CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<div class="container">
    <h1 class="my-4">Enrollment Request</h1>

    @if (submitted)
    {
        <div class="alert alert-success">
            <h4>Request Submitted</h4>
            <p>Thank you, <strong>@model.StudentName</strong>. Your enrollment request for
                <strong>@(selectedCourse?.Title ?? "the selected course")</strong> has been received.
                You will be notified of the outcome via your university email.</p>
            <a href="/courses" class="btn btn-primary">Back to Courses</a>
        </div>
    }
    else
    {
        <EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="enrollment">
            <DataAnnotationsValidator />
            <ValidationSummary class="text-danger mb-3" />

            <div class="mb-3">
                <label for="studentName" class="form-label">Full Name</label>
                <InputText id="studentName" class="form-control" @bind-Value="model.StudentName" />
                <ValidationMessage For="() => model.StudentName" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="studentId" class="form-label">Student ID</label>
                <InputText id="studentId" class="form-control" @bind-Value="model.StudentId" />
                <ValidationMessage For="() => model.StudentId" class="text-danger" />
            </div>

            <div class="mb-3">
                <label for="courseSelect" class="form-label">Course</label>
                <InputSelect id="courseSelect" class="form-select" @bind-Value="model.CourseId">
                    <option value="0">-- Select a Course --</option>
                    @foreach (var course in courses)
                    {
                        <option value="@course.Id">@course.CourseCode - @course.Title</option>
                    }
                </InputSelect>
                <ValidationMessage For="() => model.CourseId" class="text-danger" />
            </div>

            <button type="submit" class="btn btn-success">Submit Request</button>
            <a href="/courses" class="btn btn-secondary ms-2">Cancel</a>
        </EditForm>
    }
</div>

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }
    [SupplyParameterFromForm] private EnrollmentRequest model { get; set; } = new();

    private List<Course> courses = [];
    private Course? selectedCourse;
    private bool submitted;

    protected override void OnInitialized()
    {
        courses = CatalogService.GetCourses();
        if (CourseId.HasValue && model.CourseId == 0)
            model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        if (CatalogService.SubmitEnrollmentRequest(model))
        {
            selectedCourse = CatalogService.GetCourse(model.CourseId);
            submitted = true;
        }
    }
}

